    const onesIndices = [];
    const twosIndices = [];

    // Find all indices where nums[i] is 1 or 2
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            onesIndices.push(i);
        } else if (nums[i] === 2) {
            twosIndices.push(i);
